from flask import Flask, request, jsonify
import uuid
import hmac

app = Flask(__name__)

auth_codes = {}

def generate_code():
    return str(uuid.uuid4())

@app.route('/authorize', methods=['POST'])
def authorize():
    client_id = request.json.get('client_id')
    redirect_uri = request.json.get('redirect_uri')
    response_type = request.json.get('response_type')
    scope = request.json.get('scope')
    user_id = request.json.get('user_id')

    if response_type != 'code':
        return jsonify({'error': 'unsupported_response_type'}), 400

    code = generate_code()
    auth_codes[code] = user_id

    return jsonify({
        'code': code,
        'redirect_uri': redirect_uri
    })

@app.route('/token', methods=['POST'])
def token():
    client_id = request.json.get('client_id')
    code = request.json.get('code')
    redirect_uri = request.json.get('redirect_uri')

    if not auth_codes.get(code):
        return jsonify({'error': 'invalid_grant'}), 400

    user_id = auth_codes[code]
    del auth_codes[code]

    # Simple token generation, in a real application you would use a library
    token = hmac.new(str(user_id).encode(), digestmod='sha256').hexdigest()

    return jsonify({
        'access_token': token,
        'token_type': 'bearer'
    })

